function _alCodiceStato(val){if(!val)return'100000100';const k=_alNorm(val);if(_AL_STATI[k])return _AL_STATI[k];for(const[key,cod]of Object.entries(_AL_STATI)){if(k.includes(key)||key.includes(k))return cod;}return'100000100';}
function _alCodiceComune(val){if(!val)return null;const k=_alNorm(val);const e=_AL_COMUNI[k];if(e){const p=e.split(';');return{cod:p[0],prov:p[1]};}for(const[key,v]of Object.entries(_AL_COMUNI)){if(key===k||key.startsWith(k)||k.startsWith(key)){const p=v.split(';');return{cod:p[0],prov:p[1]};}}return null;}
function _alCodiceDoc(val){if(!val)return'IDENT';const k=_alNorm(val);if(_AL_DOCS[k])return _AL_DOCS[k];const a={'CARTA DI IDENTITA':'IDENT','CARTA IDENTITA':'IDENT','CI':'IDENT','IDENTITY CARD':'IDENT','ID CARD':'IDENT','PASSAPORTO':'PASOR','PASSPORT':'PASOR','PASSAPORTO ORDINARIO':'PASOR','PATENTE':'PATEN','DRIVING LICENSE':'PATEN','DRIVING LICENCE':'PATEN','CARTA IDENTITA ELETTRONICA':'IDELE','CIE':'IDELE','PERMESSO DI SOGGIORNO':'PERM','PERMESSO SOGGIORNO':'PERM'};if(a[k])return a[k];for(const[key,cod]of Object.entries(_AL_DOCS)){if(k.includes(key)||key.includes(k))return cod;}return k.substring(0,5);}
function _alRisolviLuogo(raw){if(!raw)return null;const k=_alNorm(raw);if(_AL_MOTO[k])return _alCodiceComune(_AL_MOTO[k]);for(const[mkey,mcity]of Object.entries(_AL_MOTO)){if(k.includes(mkey)||mkey.includes(k))return _alCodiceComune(mcity);}const com=_alCodiceComune(raw);if(com)return com;if(_AL_STATI[k])return{cod:_AL_STATI[k],prov:null,isStato:true};return null;}
function _alChiediCodiciMancanti(mancanti,onComplete){const ov=document.createElement('div');ov.id='_alComuneOv';ov.style.cssText='position:fixed;inset:0;background:rgba(0,0,0,.55);z-index:9999;display:flex;align-items:center;justify-content:center;padding:16px';const rows=mancanti.map((m,i)=>`<div style="margin-bottom:14px"><div style="font-size:13px;color:#555;margin-bottom:5px">?? <strong>${m.nomeComune}</strong> <span style="color:#888;font-size:12px">${m.label}</span></div><div style="display:flex;gap:8px"><input id="_alCod_${i}" placeholder="Codice 9 cifre (es. 412058091)" style="flex:1;padding:9px 11px;border:1.5px solid #ccc;border-radius:8px;font-size:14px;font-family:monospace" maxlength="9" oninput="this.value=this.value.replace(/[^0-9]/g,'')"><input id="_alProv_${i}" placeholder="Prov" style="width:58px;padding:9px 11px;border:1.5px solid #ccc;border-radius:8px;font-size:14px;text-transform:uppercase" maxlength="2"></div></div>`).join('');ov.innerHTML=`<div style="background:#fff;border-radius:16px;padding:24px;max-width:480px;width:100%;box-shadow:0 8px 32px rgba(0,0,0,.2)"><div style="font-size:17px;font-weight:700;margin-bottom:5px">Comuni non trovati</div><div style="font-size:13px;color:#666;margin-bottom:18px;line-height:1.5">Inserisci il <strong>codice a 9 cifre</strong> dalla tabella Alloggiati Web e la <strong>sigla provincia</strong>.<br>I codici vengono <strong>salvati</strong> per le prossime volte.</div>${rows}<div style="display:flex;gap:10px;margin-top:6px"><button onclick="_alAnnullaComuni()" style="flex:1;padding:11px;border:1.5px solid #ddd;background:#f5f5f5;border-radius:8px;cursor:pointer;font-size:14px">Annulla</button><button onclick="_alConfermaComuni(${mancanti.length})" style="flex:1;padding:11px;background:#1a73e8;color:#fff;border:none;border-radius:8px;cursor:pointer;font-size:14px;font-weight:600">Genera file</button></div></div>`;ov._onComplete=onComplete;ov._mancanti=mancanti;document.body.appendChild(ov);setTimeout(()=>{const f=document.getElementById('_alCod_0');if(f)f.focus();},100);}
function _alAnnullaComuni(){const ov=document.getElementById('_alComuneOv');if(ov)ov.remove();}
function _alConfermaComuni(n){const ov=document.getElementById('_alComuneOv');if(!ov)return;const mancanti=ov._mancanti;for(let i=0;i<n;i++){const cod=(document.getElementById('_alCod_'+i)||{}).value.trim();const prov=(document.getElementById('_alProv_'+i)||{}).value.trim().toUpperCase().substring(0,2);if(cod.length>=6){const nk=_alNorm(mancanti[i].nomeComune);_AL_COMUNI[nk]=cod+';'+(prov||'  ');_alSalvaComune(nk,cod,prov||'  ');}}ov.remove();if(ov._onComplete)ov._onComplete();}

function exportAlloggiati(scope='today'){
  const today=new Date().toISOString().slice(0,10);
  let items;
  if(scope==='today'){items=Object.values(ciData).filter(ci=>ci.data===today);}
  else{items=Object.values(ciData).filter(ci=>{if(!_ciHistSearch)return true;const q=_ciHistSearch.toLowerCase();const cap=ci.guests[0]||{};return ci.camera.toLowerCase().includes(q)||((cap.cognome||'')+' '+(cap.nome||'')).toLowerCase().includes(q)||ci.data.includes(q);});}
  if(items.length===0){showToast('Nessun check-in da esportare','error');return;}
  const comuniMancanti=[],visti=new Set();
  items.forEach(ci=>{ci.guests.forEach((g,gIdx)=>{
    const isIta=_alNorm(g.cittadinanza||'ITALIA').includes('ITAL');
    if(isIta&&g.luogoNascita&&!_alCodiceComune(g.luogoNascita)){const k=_alNorm(g.luogoNascita);if(!visti.has('N:'+k)){visti.add('N:'+k);comuniMancanti.push({nomeComune:g.luogoNascita,label:'nascita - '+cleanAl(g.cognome)+' '+cleanAl(g.nome)});}}
    if(gIdx===0&&g.luogoRilascio&&!_alRisolviLuogo(g.luogoRilascio)){const k=_alNorm(g.luogoRilascio);if(!visti.has('R:'+k)){visti.add('R:'+k);comuniMancanti.push({nomeComune:g.luogoRilascio,label:'rilascio - '+cleanAl(g.cognome)+' '+cleanAl(g.nome)});}}
  });});
  if(comuniMancanti.length>0){_alChiediCodiciMancanti(comuniMancanti,()=>exportAlloggiati(scope));return;}
  const toFmt=s=>{if(!s)return'          ';const c=s.replace(/-/g,'').replace(/\//g,'');if(c.length!==8)return'          ';let gg,mm,aaaa;if(/^(19|20)\d{6}$/.test(c)){aaaa=c.slice(0,4);mm=c.slice(4,6);gg=c.slice(6,8);}else{gg=c.slice(0,2);mm=c.slice(2,4);aaaa=c.slice(4,8);}return`${gg}/${mm}/${aaaa}`;};
  const nGiorni=(a,p)=>{try{const g=Math.round((new Date(p)-new Date(a))/86400000);return String(Math.min(Math.max(g,1),30)).padStart(2,'0');}catch{return'01';}};
  let lines=[];
  items.forEach(ci=>{
    const b=bookings.find(bk=>bk.dbId===ci.preId);
    const arrISO=ci.data,parISO=b?new Date(b.e).toISOString().slice(0,10):ci.data;
    ci.guests.forEach((g,gIdx)=>{
      const isCapo=gIdx===0,tipoAllog=isCapo?'16':'19';
      const cognome=padR(cleanAl(g.cognome),50),nome=padR(cleanAl(g.nome),30);
      const sesso=(_alNorm(g.sesso||'M').charAt(0)==='F')?'2':'1';
      const dataN=toFmt(g.dataNascita||'');
      const isIta=_alNorm(g.cittadinanza||'ITALIA').includes('ITAL');
      let comN='         ',provN='  ';
      if(isIta&&g.luogoNascita){const found=_alCodiceComune(g.luogoNascita);if(found){comN=found.cod;provN=padR(found.prov,2);}}
      const statoN=_alCodiceStato(isIta?'ITALIA':(g.statoNascita||g.cittadinanza||'ITALIA')).padStart(9,'0');
      const cittad=_alCodiceStato(g.cittadinanza||'ITALIA').padStart(9,'0');
      const tipoDoc=isCapo?padR(_alCodiceDoc(g.tipoDoc),5):'     ';
      const numDoc=isCapo?padR(cleanAl(g.numDoc||''),20):'                    ';
      let luogoRil='         ';
      if(isCapo&&g.luogoRilascio){const rl=_alRisolviLuogo(g.luogoRilascio);if(rl)luogoRil=rl.cod;}
      const record=tipoAllog+toFmt(arrISO)+nGiorni(arrISO,parISO)+cognome+nome+sesso+dataN+comN+provN+statoN+cittad+tipoDoc+numDoc+luogoRil;
      if(record.length!==168)console.warn('[Alloggiati] len='+record.length,g.cognome);
      lines.push(record);
    });
  });
  const content=lines.join('\r\n');
  const blob=new Blob([content],{type:'text/plain;charset=utf-8'});
  const url=URL.createObjectURL(blob);const a=document.createElement('a');
  a.href=url;a.download=`alloggiati_${today}.txt`;a.click();URL.revokeObjectURL(url);
  showToast('File generato - '+lines.length+' record','success');
}

// Helper testo Alloggiati Web
function cleanAl(s) { return (s||'').toUpperCase().normalize('NFD').replace(/[\u0300-\u036f]/g,'').replace(/[^A-Z0-9 '.,\-]/g,''); }
function padR(s, n) { const t=(s||'').substring(0,n); return t+' '.repeat(Math.max(0,n-t.length)); }
function pad(s, n)  { const t=(s||'').substring(0,n); return '0'.repeat(Math.max(0,n-t.length))+t; }



